// Generate SHA-256 hash for idempotency + extract file metadata
const crypto = require('crypto');

const items = $input.all();
const results = [];

for (const item of items) {
  // Get binary data — works for both webhook and Drive triggers
  const binaryKey = Object.keys(item.binary || {})[0];

  if (!binaryKey) {
    throw new Error('No binary data found. Ensure a CSV file was attached.');
  }

  const binaryData = item.binary[binaryKey];
  const buffer = Buffer.from(binaryData.data, 'base64');

  const hash = crypto.createHash('sha256').update(buffer).digest('hex');

  results.push({
    json: {
      source_hash: hash,
      source_file_name: binaryData.fileName || 'unknown.csv',
      _binaryKey: binaryKey
    },
    binary: item.binary
  });
}

return results;

// Validate and normalise each invoice row
// Rules: required fields, VAT math, date not future, prepare for dedup

const { DateTime } = require('luxon');

const sourceHash = $('Generate SHA-256 Hash').first().json.source_hash;
const sourceFileName = $('Generate SHA-256 Hash').first().json.source_file_name;

const items = $input.all();
const results = [];

for (const item of items) {
  const row = { ...item.json };
  const errors = [];

  // --- Required field checks ---
  if (!row.invoice_number || String(row.invoice_number).trim() === '') errors.push('Missing invoice_number');
  if (!row.supplier_number || String(row.supplier_number).trim() === '') errors.push('Missing supplier_number');
  if (!row.supplier_name  || String(row.supplier_name).trim()  === '') errors.push('Missing supplier_name');
  if (!row.department     || String(row.department).trim()     === '') errors.push('Missing department');
  if (!row.invoice_date   || String(row.invoice_date).trim()   === '') errors.push('Missing invoice_date');
  if (row.amount_excl === undefined || row.amount_excl === null || row.amount_excl === '') errors.push('Missing amount_excl');

  // --- Numeric normalisation ---
  const amount_excl_vat = parseFloat(row.amount_excl);
  const vat_rate        = row.vat_rate  ? parseFloat(row.vat_rate)  : 15.0; // Default SA VAT = 15%

  // VAT: use explicit value if present, else derive from rate
  let vat = row.vat !== undefined && row.vat !== '' && row.vat !== null
    ? parseFloat(row.vat)
    : parseFloat((amount_excl_vat * vat_rate / 100).toFixed(2));

  // amount_incl: use explicit value if present, else derive
  let amount_incl_vat = row.amount_incl !== undefined && row.amount_incl !== '' && row.amount_incl !== null
    ? parseFloat(row.amount_incl)
    : parseFloat((amount_excl_vat + vat).toFixed(2));

  // --- Math validation: amount_incl_vat = amount_excl_vat + vat (±0.01) ---
  if (errors.length === 0) {
    const diff = Math.abs((amount_excl_vat + vat) - amount_incl_vat);
    if (diff > 0.01) {
      errors.push(`VAT math mismatch: ${amount_excl_vat} + ${vat} ≠ ${amount_incl_vat} (diff=${diff.toFixed(4)})`);
    }

    // Check VAT rate consistency if vat was explicitly provided
    if (row.vat !== undefined && row.vat !== '' && row.vat !== null) {
      const expectedVat = parseFloat((amount_excl_vat * vat_rate / 100).toFixed(2));
      if (Math.abs(parseFloat(row.vat) - expectedVat) > 0.01) {
        errors.push(`VAT rate mismatch: provided vat=${row.vat}, expected ${expectedVat} at ${vat_rate}%`);
      }
    }
  }

  // --- Date validation: not in the future (Africa/Johannesburg) ---
  if (row.invoice_date && String(row.invoice_date).trim() !== '') {
    try {
      const invoiceDate = DateTime.fromISO(String(row.invoice_date).trim(), { zone: 'Africa/Johannesburg' });
      const today       = DateTime.now().setZone('Africa/Johannesburg').startOf('day');

      if (!invoiceDate.isValid) {
        errors.push(`Invalid invoice_date format: ${row.invoice_date}`);
      } else if (invoiceDate > today) {
        errors.push(`invoice_date is in the future: ${row.invoice_date}`);
      }
    } catch (e) {
      errors.push(`Could not parse invoice_date: ${row.invoice_date}`);
    }
  }

  const isValid = errors.length === 0;

  results.push({
    json: {
      invoice_number:   String(row.invoice_number  || '').trim(),
      supplier_number:  String(row.supplier_number || '').trim(),
      supplier_name:    String(row.supplier_name   || '').trim(),
      department:       String(row.department      || '').trim(),
      amount_excl_vat:  isNaN(amount_excl_vat) ? null : amount_excl_vat,
      vat:              isNaN(vat)              ? null : vat,
      amount_incl_vat:  isNaN(amount_incl_vat) ? null : amount_incl_vat,
      invoice_date:     String(row.invoice_date    || '').trim(),
      source_file_name: sourceFileName,
      source_hash:      sourceHash,
      valid:            isValid,
      validation_notes: errors.join('; ') || null
    }
  });
}

return results;

// Mark this record as duplicate — do not insert
const item = $input.first();
return [{
  json: {
    ...item.json,
    status: 'duplicate',
    validation_notes: 'Duplicate: (supplier_number, invoice_number) already exists in supplier_invoices'
  }
}];

// Mark failed validation records with status='failed'
const item = $input.first();
return [{
  json: {
    ...item.json,
    status: 'failed'
  }
}];

// Aggregate all branch results into metrics for the email summary
// Collect results from: Insert Valid Invoice, Mark as Duplicate, Mark as Failed

const allItems = $input.all();

let inserted   = 0;
let duplicates = 0;
let failed     = 0;
const errors   = [];

for (const item of allItems) {
  const status = item.json.status;
  if (status === 'inserted')  inserted++;
  if (status === 'duplicate') duplicates++;
  if (status === 'failed') {
    failed++;
    errors.push({
      invoice_number:  item.json.invoice_number  || 'N/A',
      supplier_number: item.json.supplier_number || 'N/A',
      reason:          item.json.validation_notes || 'Unknown validation error'
    });
  }
  // Also collect duplicate info if needed
  if (status === 'duplicate') {
    errors.push({
      invoice_number:  item.json.invoice_number  || 'N/A',
      supplier_number: item.json.supplier_number || 'N/A',
      reason:          item.json.validation_notes || 'Duplicate record'
    });
  }
}

const processed = inserted + duplicates + failed;

return [{
  json: {
    processed,
    inserted,
    duplicates,
    failed,
    errors: errors.slice(0, 20) // Cap at 20 rows per spec
  }
}];
